    ${jdata.map((j, i) =&gt; htl.html`&lt;tr style="border-bottom:1px solid #eee; background:${i % 2 === 0 ? '#fff' : '#f9f9f9'};"&gt;
      &lt;td style="padding:8px 12px; font-style:italic;"&gt;${j.journal}&lt;/td&gt;
      &lt;td style="padding:8px 12px; text-align:center;"&gt;${j.count}&lt;/td&gt;
    &lt;/tr&gt;`)}
  &lt;/tbody&gt;
